class User(
    val username: String,
    val email: String = "",
    val isActive: Boolean = true
) {
    // Secondary constructor
    constructor(username: String) : this(username, "$username@default.com")

    fun display() {
        println("$username ($email) Active: $isActive")
    }
}

fun main() {
    val u1 = User("alice", "alice@test.com")
    val u2 = User("bob")  // Uses secondary constructor
    u1.display()
    u2.display()
}
